import time

def fuehre_workflow_aus(log: str) -> dict:
    """Fuehrt die Kette aus, protokolliert jeden Schritt und faengt Fehler ab."""
    ergebnis = {}
    schritte = [
        ("fehler",          extrahiere_fehler,   log),
        ("zusammenfassung", fasse_zusammen,      None),
        ("empfehlung",      empfehle_massnahme,  None),
    ]

    vorige_ausgabe = log
    for name, funktion, _ in schritte:
        start = time.time()
        try:
            vorige_ausgabe = funktion(vorige_ausgabe)
            ergebnis[name] = vorige_ausgabe
            dauer = time.time() - start
            print(f"[OK]   {name:16} ({dauer:.1f}s)")
        except Exception as e:
            print(f"[FEHLER] {name}: {e}")
            ergebnis[name] = None
            break   # Kette abbrechen, aber sauber

    return ergebnis

if __name__ == "__main__":
    ausgabe = fuehre_workflow_aus("...LOG-INHALT...")
    if ausgabe.get("empfehlung"):
        print("\nEmpfehlung:", ausgabe["empfehlung"])
